var canAliceWin = function(n) {
    let remaining = n;
    let need = 10;
    let aliceTurn = true;
    while (need > 0 && remaining >= need) {
        remaining -= need;
        need -= 1;
        aliceTurn = !aliceTurn;
    }
    return !aliceTurn;
};
